class Solution {
   public:
      vector<double> solve(vector<int>& coefficients) {
         vector<double> roots;
         for (int i = 0; i < coefficients.size(); i++) {
            if (coefficients[i] != 0) roots.push_back(1 - coefficients[i]);
         }
         return roots;
      }
   };

int main() {
   int n;
   cin >> n;
   coefficients.resize(n);
   for (int i = 0; i < n; i++) {
      cin >> coefficients[i];
   }
   Solution sol;
   sol.solve(coefficients);
   return 0;
}
